import numpy as np from sklearn.feature_selection import SelectFromModelfrom sklearn.linear_model import LinearRegressionfrom sklearn.metrics import r2_scorefrom population import Populationfrom sklearn.base import clonefrom data_class import Dataimport nsga_functions as nsgaimport matplotlib.pyplot as pltimport benchmark_metrics as bmfrom ML_code import eval_model#%%dataset_id = 464population_size = 100archive_size = 100generations = 20crossover_prob = 0.78mutation_prob = 0.02tournament_param = 0.59exploration_param = 0.63seeding_prop = 0.4ones_prop = 0.01ls_param = 0.5data = Data(dataset_id)#%%def FNSGA(data, model, scorer, population_size, generations, crossover_prob, mutation_prob,          tournament_param, exploration_param,          seeding_prop, ones_prop, ls_param,          seed=None, plot=False, ls_toolbox = True):        rng = np.random.default_rng(seed)         # feature importances based on model evaluation    feat_importance = SelectFromModel(        estimator=clone(model)        ).fit(data.X, data.y).estimator_.coef_[0]         # generate initial population    pop_t = Population(population_size)    pop_t.initialize(data.n, feat_importance, seeding_prop, ones_prop, rng)    pop_t.evaluate(data, model, scorer)         # store initial pop in archive     archive = Population(population_size)    archive = nsga.update_archive(pop_t, archive, population_size)        # amount of individuals for offspring coming from LS vs ES    N_l = round(population_size * ls_param)    N_e = population_size - N_l        # iteration history for plotting     if plot:         history = []        for t in range(generations):        # set ranks/crowding on archive (needed for ND extraction and tournament select)        fronts = nsga.fast_non_dominated_sort(archive)        for front in fronts:            nsga.crowding_distance(front)            # set ranks/crowding on pop_t (needed for tournament select)        fronts_t = nsga.fast_non_dominated_sort(pop_t)        for front in fronts_t:            nsga.crowding_distance(front)                        # extract non-dominated set from archive        nd_archive = Population(0)        nd_archive.population = [ind for ind in archive.population if ind.rank == 1]                            # get (normalised) feature scores of nondominated solutions (for local search)        A = nd_archive.chromosomes        model_scores = nd_archive.fitness[:, 0]        denom = A.sum(axis=0)        denom[denom == 0] = 1        feat_scores = (A.T @ -model_scores) / denom        # Evolutionary Selection        evo_pop = nsga.evolutionary_selection(pop_t, crossover_prob, mutation_prob, tournament_param, exploration_param, len(pop_t), N_e, rng)        evo_pop.evaluate(data, model, scorer)                     LS_return = round(N_l/4)        # Local Search 1 - add        ls1 = nsga.add_local_search(nd_archive, feat_scores, LS_return, rng)                # Local Search 2 - remove        ls2 = nsga.remove_local_search(nd_archive, feat_scores, LS_return, rng)                # Local Search 3 - merge        ls3 = nsga.merge_local_search(nd_archive, LS_return, rng)                # Local Search 4 - add-remove        ls4 = nsga.add_remove_local_search(nd_archive, feat_scores, round(N_l - LS_return*3), rng)                ls_pop = Population(N_l)        ls_pop.population = [*ls1.population, *ls2.population, *ls3.population, *ls4.population]         ls_pop.evaluate(data, model, scorer)                if plot:            def _get_fitness(pop):                f = [ind.fitness for ind in pop.population if ind.fitness is not None]                return np.array(f) if f else np.empty((0, 2))            history.append({                'iteration': t + 1,                'evo': _get_fitness(evo_pop),                'ls1': _get_fitness(ls1),                'ls2': _get_fitness(ls2),                'ls3': _get_fitness(ls3),                'ls4': _get_fitness(ls4),            })        # next generation        offspring = Population(N_e + N_l)        offspring.population = [*evo_pop.population,*ls_pop.population]                rng.shuffle(offspring.population)                 # update the archive with new best solutions        archive = nsga.update_archive(offspring, archive, population_size)        pop_t = offspring        print(f"Iteration {t+1}/{generations} | ND set size: {len(nd_archive)}")    # final ND solution set     fronts = nsga.fast_non_dominated_sort(archive)    final_nd = Population(len(fronts[0]))    final_nd.population = fronts[0]        if plot:        last_fig = None        last_ax = None        for h in history:            fig, ax = plt.subplots(figsize=(7, 5))            for key, label, color, marker in [                ('evo', 'New solutions: Evolutionary Select', 'red',  'o'),                ('ls1', 'New solutions: Local Search: Add',   'orange',   '*'),                ('ls2', 'New solutions: Local Search: Remove',   'green',   '^'),                ('ls3', 'New solutions: Local Search: Merge',   'blue',   's'),                ('ls4', 'New solutions: Local Search: Add-Remove',   'purple',   'd')            ]:                d = h[key]                if len(d) == 0:                    continue                ax.scatter(d[:, 1], -d[:, 0], label=label, alpha=0.6,                           color=color, marker=marker, s=30)            ax.set_xlabel('Number of Features')            ax.set_ylabel('R²')            ax.set_title(f'Iteration {h["iteration"]}')            ax.legend(loc='lower right', fontsize=8)            plt.tight_layout()            if h["iteration"] == generations:                last_fig = fig                last_ax = ax            else:                plt.show()    return final_nd, last_fig, last_ax#%% Single Run seed = 3444import timefrom pymoo.indicators.hv import HVstart = time.time()result, fig, ax = FNSGA(        data, LinearRegression(), r2_score,         population_size, generations,        crossover_prob, mutation_prob,        tournament_param, exploration_param,        seeding_prop, ones_prop,        ls_param,        seed=seed, plot=True    )print(f"\nSeed: {seed}")print(f"Runtime: {time.time() - start:.1f}s")print(f"Final ND set size: {len(result)}") ref_point = np.array([1.1, data.n + 1])fitness = np.array([ind.fitness for ind in result.population])hv = HV(ref_point=ref_point)(fitness)print(f"Hypervolume: {hv:.4f}") ax.scatter(fitness[:, 1], -fitness[:, 0],facecolors="none",    edgecolors="black", label = "Final ND Set (from archive)")ax.legend(loc='lower right', fontsize=8)ax.set_title('Final Iteration and Final Pareto Front')plt.show()#%% Compile Results Across Seedsseed_array = np.random.choice(10000, size = 20, replace = False)extreme_1, extreme_2 = bm.compute_pareto_extremes(data, eval_model)results = bm.run_FNSGA_metrics(seed_array, data, population_size, generations, crossover_prob,                       mutation_prob,tournament_param, exploration_param,ref_point,                       extreme_1, extreme_2, seeding_prop, ones_prop, ls_param, FNSGA)#%% Build Table of Resultsimport pandas as pdtable = {}for r in results:    seeds = f"seed {r['seed']}     "    table[seeds] = {                    "": "FNSGA v0  FNSGA v1 |",                    "Hypervolume": f"{r['HV_v0']:.2f}    {r['HV_v1']:.2f} |",                    "Spread": f"{r['spread_v0']:.2f}      {r['spread_v1']:.2f} |",                    "Spacing": f"{r['spacing_v0']:.2f}      {r['spacing_v1']:.2f} |",                    "Runtime (s)": f"{r['time_v0']:.2f}     {r['time_v1']:.2f} |"}        df = pd.DataFrame(table)with pd.option_context('display.max_rows', None, 'display.max_columns', None):      print(df)#%% #The Wilcoxon signed-rank test tests the null hypothesis that two related #paired samples come from the same distribution. (from scipy.stats documentation)from scipy.stats import wilcoxonprint("Wilcoxon signed-rank test")for metric in ["HV", "spread", "spacing", "time"]:    v0 = [r[f"{metric}_v0"] for r in results]    v1 = [r[f"{metric}_v1"] for r in results]    diff = np.subtract(v0, v1)    res = wilcoxon(diff)    print(f"{metric}: (statistic, p-val) = ({res.statistic:.4f}, {res.pvalue:.8f})")